## ✅ 2. Fonction `register_object()` à jour

Cette fonction :
- crée l’objet s’il n’existe pas ;
- enregistre son type, et crée un objet pour ce type s’il n’existe pas, avec `derives_from Object` si nouveau ;
- enregistre les métadonnées en créant un objet `Meta` pour chaque clé de méta s’il n’existe pas ;
- enregistre les relations, en créant un objet `Relation` pour chaque type de relation s’il n’existe pas, avec `derives_from Relation`.

```python
def register_object(self, obj_data):
    """
    Enregistre un objet complet dans la base de données avec sémantisation.
    """
    if not isinstance(obj_data, dict):
        obj_data = {"nom": str(obj_data)}

    if "nom" not in obj_data:
        raise ValueError("L'objet doit avoir un attribut 'nom'.")

    obj_name = obj_data["nom"]
    obj_id = self.get_or_create_object(obj_name)

    # Gestion du type
    obj_type = obj_data.get("type")
    if obj_type:
        type_id = self.get_or_create_object(obj_type)
        self.add_metadata(obj_id, "type", obj_type)

        # S'assurer que le type est bien enregistré comme un objet de type "Object" (ou "Type")
        if not self.has_metadata(type_id, "type"):
            self.add_metadata(type_id, "type", "Object")
            self.add_relation(type_id, self.get_or_create_object("Object"), "derives_from")

    # Autres clés simples -> métadonnées
    for key, value in obj_data.items():
        if key in ["nom", "name", "type", "metas", "relations"]:
            continue
        meta_id = self.get_or_create_object(key)
        self.add_metadata(obj_id, key, value)

        # Déclaration de la clé comme une méta
        if not self.has_metadata(meta_id, "type"):
            self.add_metadata(meta_id, "type", "Meta")
            self.add_relation(meta_id, self.get_or_create_object("Object"), "derives_from")

        # auto-meta_of
        self.add_relation(meta_id, obj_id, "meta_of")

    # Métas explicites
    if "metas" in obj_data:
        metas = obj_data["metas"]
        if isinstance(metas, dict):
            metas = [metas]
        for meta_dict in metas:
            for meta_key, meta_value in meta_dict.items():
                meta_id = self.get_or_create_object(meta_key)
                self.add_metadata(obj_id, meta_key, meta_value)
                if not self.has_metadata(meta_id, "type"):
                    self.add_metadata(meta_id, "type", "Meta")
                    self.add_relation(meta_id, self.get_or_create_object("Object"), "derives_from")
                self.add_relation(meta_id, obj_id, "meta_of")

    # Relations explicites
    if "relations" in obj_data:
        for rel in obj_data["relations"]:
            if isinstance(rel, dict) and "type" in rel and "target" in rel:
                rel_type = rel["type"]
                target_name = rel["target"]

                # Vérifier que le type de relation est bien enregistré comme Relation
                rel_obj_id = self.get_or_create_object(rel_type)
                if not self.has_metadata(rel_obj_id, "type"):
                    self.add_metadata(rel_obj_id, "type", "Relation")
                    self.add_relation(rel_obj_id, self.get_or_create_object("Relation"), "derives_from")
                    self.add_relation(rel_obj_id, rel_obj_id, "meta_of")

                target_id = self.get_or_create_object(target_name)
                self.add_relation(obj_id, target_id, rel_type)
